public class Hello {
    public static void main(String[] args) {
        System.out.println("Hello, World!");

        // Faktorial
        int n = 5;
        int result = 1;
        for (int i = 1; i <= n; i++) {
            result *= i;
        }
        System.out.println("Faktoriali i " + n + " eshte: " + result);

        // Stream API
        java.util.List<Integer> numrat = java.util.List.of(1,2,3,4,5);
        numrat.stream()
              .map(x -> x * x)
              .forEach(x -> System.out.print(x + " "));
    }
}

