// Shembull C++
#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::cout << "Hello, World!" << std::endl;

    // Faktorial
    int n = 5, result = 1;
    for (int i = 1; i <= n; i++)
        result *= i;
    std::cout << "Faktoriali i " << n << " eshte: " << result << std::endl;

    // STL algorithm
    std::vector<int> numrat = {1, 2, 3, 4, 5};
    std::transform(numrat.begin(), numrat.end(), numrat.begin(),
                   [](int x) { return x * x; });
    for (int x : numrat)
        std::cout << x << " ";
    return 0;
}

