// Shembull Go
package main

import "fmt"

func factorial(n int) int {
    if n <= 1 {
        return 1
    }
    return n * factorial(n-1)
}

func main() {
    fmt.Println("Hello, World!")

    n := 5
    fmt.Printf("Faktoriali i %d eshte: %d\n", n, factorial(n))

    // Goroutine dhe channel
    ch := make(chan int)
    go func() {
        sum := 0
        for i := 1; i <= 5; i++ {
            sum += i
        }
        ch <- sum
    }()
    result := <-ch
    fmt.Printf("Shuma: %d\n", result)
}

