// Shembull Rust
fn factorial(n: u64) -> u64 {
    match n {
        0 | 1 => 1,
        _ => n * factorial(n - 1),
    }
}

fn main() {
    println!("Hello, World!");

    let n = 5;
    println!("Faktoriali i {} eshte: {}", n, factorial(n));

    // Iterator
    let katror: Vec<i32> = (1..=5).map(|x| x * x).collect();
    println!("Katroret: {:?}", katror);

    // Ownership
    let s = String::from("Rust");
    println!("Gjuha: {}", s);
}

